const cfg = $('Config').first().json;
const patterns = cfg.feedPatterns.map(p => new RegExp(p, 'i'));
const feeds = $input.all().map(i => i.json);
const matched = feeds.filter(f => patterns.some(p => p.test(f.title || '')));
if (!matched.length) throw new Error('no feeds matched cfg.feedPatterns');
return matched.map(f => ({ json: { feedId: f.id, feedTitle: f.title } }));

const cfg = $('Config').first().json;
const skip = new RegExp(cfg.skipPattern, 'i');
const priority = new RegExp(cfg.priorityPattern, 'i');
const entries = $input.all().map(i => i.json);
const isPriority = e => priority.test(`${e.title} ${e.url}`);
const kept = entries.filter(e => isPriority(e) || !skip.test(`${e.title} ${e.url}`));
if (!kept.length) throw new Error('no entries survived skip/priority filtering');
return kept.map(e => ({ json: { ...e, priority: isPriority(e) } }));

function tokens(t) {
  return new Set((t || '').toLowerCase().replace(/[^a-z0-9 ]/g, '').split(' ').filter(w => w.length > 3));
}
function similarity(a, b) {
  const ta = tokens(a), tb = tokens(b);
  const inter = [...ta].filter(w => tb.has(w)).length;
  return inter / Math.max(ta.size, tb.size, 1);
}
const cfg = $('Config').first().json;
const items = $input.all().map(i => i.json).sort((a, b) => (b.priority ? 1 : 0) - (a.priority ? 1 : 0));
const kept = [];
for (const e of items) {
  if (!kept.some(k => similarity(k.title, e.title) > cfg.dedupThreshold)) kept.push(e);
}
return kept.map(e => ({
  json: {
    title: e.title,
    published_at: e.published_at,
    priority: e.priority,
    snippet: (e.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().split(' ').slice(0, cfg.snippetWords).join(' ')
  }
}));

const cfg = $('Config').first().json;
const entries = $input.all().map(i => i.json);
if (!entries.length) throw new Error('no entries to summarize');
const text = entries.map(e => `${e.priority ? '[P] ' : '- '}${e.title} (${e.published_at.slice(0, 10)}): ${e.snippet}`).join('\n');
const sat = $now.plus({ days: 1 }).toFormat('MMM d');
const sun = $now.plus({ days: 2 }).toFormat('MMM d');
let userPrompt = cfg.userPromptTemplate
  .replaceAll('{{MAX_WORDS}}', cfg.maxWordsPerBullet)
  .replaceAll('{{SAT}}', sat)
  .replaceAll('{{SUN}}', sun)
  .replaceAll('{{ENTRIES}}', text);
for (const name of cfg.sections) {
  userPrompt = userPrompt.replaceAll(`{{MAX_${name.toUpperCase()}}}`, cfg.maxItems[name]);
}
const properties = Object.fromEntries(cfg.sections.map(name => [name, { type: 'array', items: { type: 'string' } }]));
const payload = {
  model: 'qwen3',
  temperature: 0.3,
  response_format: { type: 'json_schema', json_schema: { name: 'digest', schema: { type: 'object', properties, required: cfg.sections } } },
  messages: [
    { role: 'system', content: cfg.systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};
return [{ json: { payload } }];

function tokens(t) {
  return new Set((t || '').toLowerCase().replace(/[^a-z0-9 ]/g, '').split(' ').filter(w => w.length > 3));
}
function similarity(a, b) {
  const ta = tokens(a), tb = tokens(b);
  const inter = [...ta].filter(w => tb.has(w)).length;
  return inter / Math.max(ta.size, tb.size, 1);
}
const cfg = $('Config').first().json;
const skip = new RegExp(cfg.skipPattern, 'i');
const raw = JSON.parse($input.first().json.choices[0].message.content);
function clean(list, max) {
  const kept = [];
  for (const item of (list || [])) {
    if (skip.test(item)) continue;
    if (kept.some(k => similarity(k, item) > 0.6)) continue;
    kept.push(item);
    if (kept.length >= max) break;
  }
  return kept;
}
const result = Object.fromEntries(cfg.sections.map(name => [name, clean(raw[name], cfg.maxItems[name])]));
if (Object.values(result).every(list => !list.length)) throw new Error('QA: digest empty after cleanup');
return [{ json: result }];

const d = $input.first().json;
const s = $getWorkflowStaticData('global');
s.digest = { week: d.week, weekend: d.weekend, updated: $now.toISO() };
return [{ json: s.digest }];
